#include <algorithm>

string licenseKeyFormatting(string s, int k) {
    string reformattedKey;
    int groupSize = k;
    int groupCount = 0;

    for (char c : s) {
        if (groupCount < s.length() - 1 && c == '-') {
            if (groupSize > 0) {
                reformattedKey += string(groupSize, '-');
                groupSize = k;
            }
            groupCount++;
        } else {
            if (groupSize < k) {
                groupSize += 1;
            }
            reformattedKey += c;
            groupCount++;
        }
    }

    if (groupSize > 0) {
        reformattedKey += string(groupSize, '-');
    }

    return reformattedKey;
}
